func prettifyPath(in string, b filepathPathBridge) string {
	if filepath.Ext(in) == "" {

		if len(in) < 2 {
			return b.Separator()
		}
		return b.Join(in, "index.html")
	}
	name, ext := fileAndExt(in, b)
	if name == "index" {

		return b.Clean(in)
	}

	return b.Join(b.Dir(in), name, "index"+ext)
}
